'use client'

import { motion } from 'framer-motion'
import { Check, Clock, AlertCircle, Heart } from 'lucide-react'

const activityData = [
  {
    id: 1,
    type: 'donation',
    title: 'Donation Accepted',
    description: 'Meals for All picked up 15kg of bread',
    time: '2 hours ago',
    icon: Check,
    color: 'emerald',
  },
  {
    id: 2,
    type: 'pending',
    title: 'Donation Pending',
    description: 'Fresh vegetables ready for pickup',
    time: '30 minutes ago',
    icon: Clock,
    color: 'orange',
  },
  {
    id: 3,
    type: 'donation',
    title: 'Donation Accepted',
    description: 'Community Care collected 8kg of pastries',
    time: '5 hours ago',
    icon: Check,
    color: 'emerald',
  },
  {
    id: 4,
    type: 'expiring',
    title: 'Expiring Soon',
    description: 'Dairy items expiring in 2 days',
    time: '1 day ago',
    icon: AlertCircle,
    color: 'red',
  },
]

const ngoRequestsData = [
  {
    id: 1,
    name: 'Meals for All',
    request: 'Looking for fresh vegetables',
    quantity: '20-25 kg',
    priority: 'High',
    image: 'M',
  },
  {
    id: 2,
    name: 'Community Care',
    request: 'Bakery items needed',
    quantity: '10-15 kg',
    priority: 'Medium',
    image: 'CC',
  },
  {
    id: 3,
    name: 'Food for Tomorrow',
    request: 'Any prepared foods',
    quantity: '5-10 kg',
    priority: 'Low',
    image: 'FF',
  },
]

export function ActivityFeed() {
  return (
    <motion.div
      className="glass p-6 rounded-2xl border border-white/10"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.6, duration: 0.4 }}
    >
      <h3 className="text-lg font-semibold text-foreground mb-4">
        Recent Activity
      </h3>
      <div className="space-y-4">
        {activityData.map((activity, index) => {
          const Icon = activity.icon
          const colorClasses = {
            emerald: 'bg-emerald-500/20 text-emerald-500',
            orange: 'bg-orange-500/20 text-orange-500',
            red: 'bg-red-500/20 text-red-500',
          }

          return (
            <motion.div
              key={activity.id}
              className="flex items-start gap-4 p-3 rounded-lg hover:bg-white/5 transition-colors"
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.6 + index * 0.05 }}
            >
              <div className={`p-2 rounded-lg ${colorClasses[activity.color]}`}>
                <Icon size={16} />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-foreground">
                  {activity.title}
                </p>
                <p className="text-xs text-muted-foreground truncate">
                  {activity.description}
                </p>
              </div>
              <p className="text-xs text-muted-foreground whitespace-nowrap">
                {activity.time}
              </p>
            </motion.div>
          )
        })}
      </div>
    </motion.div>
  )
}

export function NGORequestsPanel() {
  return (
    <motion.div
      className="glass p-6 rounded-2xl border border-white/10"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.7, duration: 0.4 }}
    >
      <h3 className="text-lg font-semibold text-foreground mb-4">
        NGO Requests
      </h3>
      <div className="space-y-3">
        {ngoRequestsData.map((ngo, index) => (
          <motion.div
            key={ngo.id}
            className="flex items-start justify-between p-4 rounded-lg hover:bg-white/5 transition-colors group cursor-pointer"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.7 + index * 0.05 }}
            whileHover={{ x: 4 }}
          >
            <div className="flex items-start gap-3 flex-1">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center text-white text-sm font-semibold flex-shrink-0">
                {ngo.image}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-foreground">{ngo.name}</p>
                <p className="text-xs text-muted-foreground">{ngo.request}</p>
                <p className="text-xs text-muted-foreground mt-1">
                  Quantity: <span className="text-emerald-500">{ngo.quantity}</span>
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <span
                className={`text-xs font-semibold px-2 py-1 rounded-full ${
                  ngo.priority === 'High'
                    ? 'bg-red-500/20 text-red-500'
                    : ngo.priority === 'Medium'
                      ? 'bg-orange-500/20 text-orange-500'
                      : 'bg-blue-500/20 text-blue-500'
                }`}
              >
                {ngo.priority}
              </span>
              <motion.button
                className="p-2 rounded-lg bg-primary/10 text-primary opacity-0 group-hover:opacity-100 transition-opacity"
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.95 }}
              >
                <Heart size={16} />
              </motion.button>
            </div>
          </motion.div>
        ))}
      </div>
    </motion.div>
  )
}
